import org.springframework.graphql.data.method.annotation.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

record Product(String id, String name, double price) {}

@Controller
class ProductQueryController {

    // Schema: product(id: ID!): Product
    // ID! in schema → String in Java (GraphQL ID is opaque, serialized as String)
    @QueryMapping
    public Product product(@Argument String id) {
        // Simulated lookup:
        if ("PROD-001".equals(id)) return new Product(id, "iPhone 15", 134900.0);
        return null; // nullable schema: Product (not Product!)
    }

    // Schema: products(category: String): [Product!]!
    // Nullable argument: category is optional (null = all categories)
    @QueryMapping
    public List<Product> products(@Argument String category) {
        List<Product> all = List.of(
            new Product("P1", "iPhone 15", 134900.0),
            new Product("P2", "Samsung S24", 79999.0)
        );
        if (category == null) return all;
        return all.stream()
            .filter(p -> p.name().contains(category))
            .toList();
    }

    // Schema: searchProducts(keyword: String!, limit: Int): [Product!]!
    // Multiple arguments: each with @Argument
    @QueryMapping
    public List<Product> searchProducts(
            @Argument String keyword,
            @Argument Integer limit) {  // Integer (nullable) for optional limit
        int maxResults = limit != null ? limit : 10;
        return List.of(new Product("P1", keyword + " result", 9999.0))
            .stream().limit(maxResults).toList();
    }
}

