class ProductQueryControllerTest {
    @Autowired ProductQueryController ctrl;
    @Test void product_found() { assertNotNull(ctrl.product("PROD-001")); }
    @Test void product_notFound() { assertNull(ctrl.product("PROD-999")); }
    @Test void products_allCategories() { assertEquals(2, ctrl.products(null).size()); }
    @Test void search_withLimit() { assertEquals(1, ctrl.searchProducts("phone", 5).size()); }
}

import org.springframework.graphql.data.method.annotation.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

// Input type: maps from GraphQL 'input CreateProductInput' SDL
record CreateProductInput(String name, Double priceAmount, String category, String sellerId) {}
record Product2(String id, String name, double price) {}

@Controller
class ProductMutationController {
    private final Map<String, Product2> db = new ConcurrentHashMap<>();

    // Schema: createProduct(input: CreateProductInput!): Product!
    @MutationMapping
    public Product2 createProduct(@Argument CreateProductInput input) {
        String id = "PROD-" + System.nanoTime();
        Product2 p = new Product2(id, input.name(), input.priceAmount());
        db.put(id, p);
        return p;
    }

    // Schema: updatePrice(productId: ID!, newPrice: Float!): Product!
    @MutationMapping
    public Product2 updatePrice(
            @Argument String productId,
            @Argument Double newPrice) {
        Product2 existing = db.get(productId);
        if (existing == null) throw new RuntimeException("Product not found: " + productId);
        Product2 updated = new Product2(productId, existing.name(), newPrice);
        db.put(productId, updated);
        return updated;
    }

    // Schema: deleteProduct(id: ID!): Boolean!
    @MutationMapping
    public Boolean deleteProduct(@Argument String id) {
        return db.remove(id) != null;
    }
}

@SpringBootTest
class ProductMutationTest {
    @Autowired ProductMutationController ctrl;

    @Test void createProduct_returnsWithId() {
        Product2 p = ctrl.createProduct(new CreateProductInput("Galaxy S24", 79999.0, "ELECTRONICS", "SELL-1"));
        assertNotNull(p.id());
        assertTrue(p.id().startsWith("PROD-"));
        assertEquals("Galaxy S24", p.name());
    }
    @Test void updatePrice_updatesValue() {
        Product2 created = ctrl.createProduct(new CreateProductInput("iPhone", 134900.0, "ELECTRONICS", "SELL-2"));
        Product2 updated = ctrl.updatePrice(created.id(), 124900.0);
        assertEquals(124900.0, updated.price());
    }
    @Test void deleteProduct_returnsTrue() {
        Product2 created = ctrl.createProduct(new CreateProductInput("Test", 999.0, "BOOKS", "SELL-3"));
        assertTrue(ctrl.deleteProduct(created.id()));
        assertFalse(ctrl.deleteProduct(created.id())); // already deleted
    }
}

