record ProductItem(String id, String name, String sellerId) {}
record Review(String id, int rating, String comment) {}
record Seller(String id, String name, double rating) {}

@Controller
class ProductFieldController {
    // Simulated databases:
    private final Map<String, List<Review>> reviewsByProduct = Map.of(
        "P1", List.of(new Review("R1", 5, "Excellent!"), new Review("R2", 4, "Good product")),
        "P2", List.of(new Review("R3", 3, "Average"))
    );
    private final Map<String, Seller> sellersById = Map.of(
        "SELL-1", new Seller("SELL-1", "Flipkart Seller A", 4.8),
        "SELL-2", new Seller("SELL-2", "Cloudtail India", 4.5)
    );

    // Schema: type Product { reviews: [Review!]! }
    // Called ONCE PER PRODUCT that has 'reviews' in the query
    // N+1 risk: 10 products → 10 calls to reviewsByProduct.get()
    @SchemaMapping(typeName = "Product")
    public List<Review> reviews(ProductItem product) {
        System.out.println("Fetching reviews for: " + product.id()); // N+1 visible here
        return reviewsByProduct.getOrDefault(product.id(), List.of());
    }

    // Schema: type Product { seller: Seller! }
    // Also called once per product — N+1 risk!
    @SchemaMapping(typeName = "Product")
    public Seller seller(ProductItem product) {
        return sellersById.getOrDefault(product.sellerId(),
            new Seller("UNKNOWN", "Unknown Seller", 0.0));
    }
}

