// Domain exception:
class ProductNotFoundException extends RuntimeException {
    private final String productId;
    ProductNotFoundException(String id) {
        super("Product not found: " + id);
        this.productId = id;
    }
    String getProductId() { return productId; }
}

// GraphQL exception resolver:
@Component
class GraphQlExceptionHandler extends DataFetcherExceptionResolverAdapter {
    @Override
    protected GraphQLError resolveToSingleError(
            Throwable ex, DataFetchingEnvironment env) {
        if (ex instanceof ProductNotFoundException pnfe) {
            return GraphQLError.newError()
                .errorType(ErrorType.NOT_FOUND)
                .message(pnfe.getMessage())
                .path(env.getExecutionStepInfo().getPath().toList())
                .build();
        }
        // Other exceptions: let Spring's default handler manage
        return null;
    }
}

@Controller
class SafeProductController {
    @QueryMapping
    public Object safeProduct(@Argument String id) {
        if ("NOT-EXIST".equals(id)) throw new ProductNotFoundException(id);
        return new java.util.HashMap<String,Object>() {{ put("id", id); put("name", "Test Product"); }};
    }
}

