    @Test void exception_constructed() {
        ProductNotFoundException ex = new ProductNotFoundException("PROD-999");
        assertEquals("Product not found: PROD-999", ex.getMessage());
        assertEquals("PROD-999", ex.getProductId());
    }
    @Test void resolver_component_exists() {
        GraphQlExceptionHandler handler = new GraphQlExceptionHandler();
        assertNotNull(handler);
        // In real test: use @GraphQlTest + GraphQlTester to verify error in response
    }
}

