import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.stream.Collectors;
import java.util.stream.IntStream;

record ProductItem2(String id, String name, double price, String category) {}
record ProductFilter2(String category, Double minPrice, Double maxPrice) {}
record ProductPage2(List<ProductItem2> items, int total, int page, int size, boolean hasNext) {}

@Service
class ProductPaginationService {
    // Simulated product database (50 products):
    private final List<ProductItem2> allProducts = IntStream.range(1, 51)
        .mapToObj(i -> new ProductItem2("P" + i, "Product " + i, i * 1000.0,
            i % 2 == 0 ? "ELECTRONICS" : "CLOTHING"))
        .collect(Collectors.toList());

    public ProductPage2 findProducts(ProductFilter2 filter, int page, int size) {
        List<ProductItem2> filtered = allProducts.stream()
            .filter(p -> filter == null || filter.category() == null ||
                         p.category().equals(filter.category()))
            .filter(p -> filter == null || filter.minPrice() == null ||
                         p.price() >= filter.minPrice())
            .collect(Collectors.toList());

        int total = filtered.size();
        int from = page * size;
        List<ProductItem2> pageItems = filtered.stream().skip(from).limit(size).toList();
        boolean hasNext = (from + size) < total;
        return new ProductPage2(pageItems, total, page, size, hasNext);
    }
}

@Controller
class PaginatedProductController {
    private final ProductPaginationService svc;
    PaginatedProductController(ProductPaginationService s) { svc = s; }

    @QueryMapping
    public ProductPage2 products(
            @Argument ProductFilter2 filter,
            @Argument(name = "page") int page,
            @Argument(name = "size") int size) {
        return svc.findProducts(filter, page, size);
    }
}

@SpringBootTest
class PaginationTest {
    @Autowired PaginatedProductController ctrl;
    @Autowired ProductPaginationService svc;

    @Test void page0_returnsFirstBatch() {
        ProductPage2 page = svc.findProducts(null, 0, 10);
        assertEquals(10, page.items().size());
        assertEquals(50, page.total());
        assertTrue(page.hasNext());
    }
    @Test void lastPage_hasNextFalse() {
        ProductPage2 page = svc.findProducts(null, 4, 10); // page 4 = items 40-49
        assertEquals(10, page.items().size());
        assertFalse(page.hasNext()); // 40+10=50 = total, no next
    }
}

