@Service
class FlipkartDataService {
    final Map<String,FlipkartProduct> products=new ConcurrentHashMap<>();
    final Map<String,FlipkartCategory> categories=Map.of("CAT-1",new FlipkartCategory("CAT-1","Electronics"),"CAT-2",new FlipkartCategory("CAT-2","Clothing"));
