    GqlProduct(String name,double price,String category){this.name=name;this.price=price;this.category=category;}
    String getId(){return id;} String getName(){return name;}
    double getPrice(){return price;} String getCategory(){return category;}
    boolean isInStock(){return inStock;}
}

interface GqlProductRepository extends JpaRepository<GqlProduct,String>{
    List<GqlProduct> findByCategory(String category);
    List<GqlProduct> findByNameContainingIgnoreCase(String keyword);
}

// GraphQL schema maps to JPA entity:
// type Product { id: ID! name: String! price: Float! category: String! inStock: Boolean! }
// Spring GraphQL: entity field 'name' → schema field 'name' (property access by convention)
// No @SchemaMapping needed for simple field access — Spring uses reflection

@Controller
class JpaProductController {
    private final GqlProductRepository repo;
    JpaProductController(GqlProductRepository r){repo=r;}
    @QueryMapping Optional<GqlProduct> product(@Argument String id){return repo.findById(id);}
    @QueryMapping List<GqlProduct> products(@Argument String category){
        return category!=null?repo.findByCategory(category):repo.findAll();
    }
    @MutationMapping GqlProduct createProduct(@Argument String name,@Argument Double price,@Argument String category){
        return repo.save(new GqlProduct(name,price,category));
    }
}

