import java.util.concurrent.*;

record SynthItem(String id,String name,double price,String sellerId){}
record SynthSeller(String id,String name){}
record SynthItemInput(String name,double price,String sellerId){}
record SynthPage(List<SynthItem> items,int total,boolean hasNext){}

@Service
class SynthItemStore {
    final Map<String,SynthItem> db=new ConcurrentHashMap<>();
    final Map<String,SynthSeller> sellers=Map.of("S1",new SynthSeller("S1","Cloudtail"),"S2",new SynthSeller("S2","WS Retail"));
    SynthItem create(SynthItemInput inp){String id="I-"+System.nanoTime();SynthItem it=new SynthItem(id,inp.name(),inp.price(),inp.sellerId());db.put(id,it);return it;}
    SynthPage page(int pg,int sz){List<SynthItem> all=new ArrayList<>(db.values());int t=all.size();return new SynthPage(all.stream().skip((long)pg*sz).limit(sz).toList(),t,(pg+1)*sz<t);}
}

@Controller
class SynthGqlController {
    private final SynthItemStore store;
    SynthGqlController(SynthItemStore s){store=s;}
    @QueryMapping SynthItem item(@Argument String id){SynthItem it=store.db.get(id);if(it==null)throw new RuntimeException("Item not found: "+id);return it;}
    @QueryMapping SynthPage items(@Argument int page,@Argument int size){return store.page(page,size);}
    @MutationMapping SynthItem createItem(@Argument SynthItemInput input){return store.create(input);}
    @SchemaMapping(typeName="Item") SynthSeller seller(SynthItem it){return store.sellers.getOrDefault(it.sellerId(),new SynthSeller("UNKNOWN","Unknown"));}
}

